#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int hardness, tensile;
        double carbon;
        scanf("%d %lf %d", &hardness, &carbon, &tensile);
        int h = hardness > 50;
        int c = carbon < 0.7;
        int t = tensile > 5600;
        if (h && c && t) {
            printf("10\n");
        } else if (h && c) {
            printf("9\n");
        } else if (c && t) {
            printf("8\n");
        } else if (h && t) {
            printf("7\n");
        } else if (h || c || t) {
            printf("6\n");
        } else {
            printf("5\n");
        }
    }
    return 0;
}

