code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int hardness = Integer.parseInt(st.nextToken());
            double carbon = Double.parseDouble(st.nextToken());
            int tensile = Integer.parseInt(st.nextToken());
            boolean h = hardness > 50;
            boolean c = carbon < 0.7;
            boolean t = tensile > 5600;
            int grade;
            if (h && c && t) grade = 10;
            else if (h && c) grade = 9;
            else if (c && t) grade = 8;
            else if (h && t) grade = 7;
            else if (h || c || t) grade = 6;
            else grade = 5;
            sb.append(grade).append('\n');
        }
        System.out.print(sb.toString());
    }
}

