        parts = data[i].split()
        hardness = int(parts[0])
        carbon = float(parts[1])
        tensile = int(parts[2])
        h = hardness > 50
        c = carbon < 0.7
        t = tensile > 5600
        if h and c and t:
            out.append('10')
        elif h and c:
            out.append('9')
        elif c and t:
            out.append('8')
        elif h and t:
            out.append('7')
        elif h or c or t:
            out.append('6')
        else:
            out.append('5')
